var ENGINE_SRC = "(function(){\n  if(window.__whEngine) return; window.__whEngine = true;\n  var WKEY = 'vnm-weather';\n  var lastRaw = null, store = { enabled:false, coverDialog:true, effects:[], random:{} };\n  var inst = {};                 /* id -> {canvas,api,inst,code} */\n  var ptr = { cx:0, cy:0, x:0, y:0, px:0, py:0, vx:0, vy:0, down:false, t:0, moved:0 };\n  var rnd = { ids:null, last:0 };\n  var boundDocs = [];\n  var lastT = 0, downLayer = false;\n\n  function now(){ return (window.performance&&performance.now)?performance.now():Date.now(); }\n\n  function readStore(){\n    try{\n      var raw = localStorage.getItem(WKEY);\n      if(raw !== lastRaw){\n        lastRaw = raw;\n        store = raw ? JSON.parse(raw) : { enabled:false, effects:[], random:{} };\n        store.effects = store.effects || []; store.random = store.random || {};\n        store.effects.forEach(function(e){ var r=inst[e.id]; if(r) r.api.params = e.params||{}; });\n      }\n    }catch(e){}\n  }\n\n  function findOverlay(){\n    try{\n      var b = document.getElementById('vnm-bg'); if(b&&b.parentNode) return b.parentNode;\n      var ifr = document.querySelectorAll('iframe');\n      for(var i=0;i<ifr.length;i++){ try{ var d=ifr[i].contentDocument; if(d){ var bb=d.getElementById('vnm-bg'); if(bb&&bb.parentNode) return bb.parentNode; } }catch(e){} }\n    }catch(e){}\n    return null;\n  }\n\n  function bindPtr(doc){\n    if(!doc || boundDocs.indexOf(doc)>=0) return; boundDocs.push(doc);\n    function mv(e){ ptr.cx=(e.clientX!=null?e.clientX:0); ptr.cy=(e.clientY!=null?e.clientY:0); ptr.moved=now(); }\n    try{\n      doc.addEventListener('pointermove', mv, {passive:true});\n      doc.addEventListener('pointerdown', function(e){ ptr.down=true; mv(e); }, {passive:true});\n      doc.addEventListener('pointerup', function(){ ptr.down=false; }, {passive:true});\n    }catch(e){}\n  }\n\n  function ensureLayer(ov){\n    var doc = ov.ownerDocument;\n    var layer = ov.querySelector('#vnm-weather');\n    if(!layer){\n      layer = doc.createElement('div');\n      layer.id = 'vnm-weather';\n      layer.style.cssText = 'position:absolute;inset:0;pointer-events:none;z-index:999990;overflow:hidden;';\n      ov.appendChild(layer);\n    }\n    var targetZ = (store.coverDialog === false) ? '3' : '999990';\n    if(layer.style.zIndex !== targetZ){\n      layer.style.zIndex = targetZ;\n    }\n    return layer;\n  }\n\n  function makeApi(canvas){\n    var ctx2 = canvas.getContext('2d');\n    return { canvas:canvas, ctx:ctx2, width:0, height:0, dpr:1, params:{}, pointer:ptr, TOP:window,\n      now:now, rand:function(a,b){return a+Math.random()*(b-a);}, randInt:function(a,b){return a+Math.floor(Math.random()*(b-a+1));} };\n  }\n\n  function instance(layer, eff){\n    var r = inst[eff.id];\n    if(r && r.code===eff.code) return r;\n    if(r){ try{ if(r.inst&&r.inst.destroy)r.inst.destroy(); if(r.canvas&&r.canvas.parentNode)r.canvas.parentNode.removeChild(r.canvas);}catch(e){} }\n    var doc = layer.ownerDocument;\n    var canvas = doc.createElement('canvas');\n    canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;display:none;';\n    layer.appendChild(canvas);\n    var api = makeApi(canvas); api.params = eff.params||{};\n    var ins = null;\n    try{ ins = (new Function('api','return('+eff.code+')(api);'))(api); }catch(e){ ins=null; }\n    r = inst[eff.id] = { canvas:canvas, api:api, inst:ins, code:eff.code };\n    return r;\n  }\n\n  function sizeCanvas(r, w, h){\n    var dpr = Math.min(2, window.devicePixelRatio||1);\n    var cw = Math.max(1,Math.round(w*dpr)), ch = Math.max(1,Math.round(h*dpr));\n    if(r.canvas.width!==cw || r.canvas.height!==ch){\n      r.canvas.width=cw; r.canvas.height=ch;\n      r.api.ctx.setTransform(dpr,0,0,dpr,0,0);\n      r.api.width=w; r.api.height=h; r.api.dpr=dpr;\n      if(r.inst&&r.inst.resize){ try{ r.inst.resize(w,h); }catch(e){} }\n    }\n  }\n\n  function activeSet(){\n    var enabled = store.effects.filter(function(e){return e.enabled;});\n    var fixed = enabled.filter(function(e){return e.fixed;});\n    var R = store.random||{};\n    if(!R.on) return enabled.map(function(e){return e.id;});\n    var pool = enabled.filter(function(e){return !e.fixed;});\n    var nowMs = Date.now(); var iv = Math.max(3,(R.interval||20))*1000;\n    if(rnd.ids===null || (nowMs-rnd.last)>=iv){\n      rnd.last = nowMs;\n      var lo=Math.max(0,R.comboMin||1), hi=Math.max(lo,R.comboMax||2);\n      var k = pool.length ? (lo+Math.floor(Math.random()*(Math.min(hi,pool.length)-lo+1))) : 0;\n      var copy=pool.slice(), pick=[];\n      for(var i=0;i<k&&copy.length;i++){ var j=Math.floor(Math.random()*copy.length); pick.push(copy.splice(j,1)[0].id); }\n      rnd.ids=pick;\n    }\n    return fixed.map(function(e){return e.id;}).concat(rnd.ids||[]);\n  }\n\n  function teardown(){\n    try{ for(var k in inst){ var r=inst[k]; if(r.inst&&r.inst.destroy)r.inst.destroy(); if(r.canvas&&r.canvas.parentNode)r.canvas.parentNode.removeChild(r.canvas); } }catch(e){}\n    inst = {};\n    var ov=findOverlay(); if(ov){ var l=ov.querySelector('#vnm-weather'); if(l&&l.parentNode)l.parentNode.removeChild(l); }\n    downLayer=false;\n  }\n\n  function loop(){\n    requestAnimationFrame(loop);\n    readStore();\n    if(!store.enabled){ if(downLayer||Object.keys(inst).length){ teardown(); } return; }\n    var ov = findOverlay(); if(!ov) return;\n    downLayer = true;\n    bindPtr(ov.ownerDocument); bindPtr(document);\n    var layer = ensureLayer(ov);\n    var rect = ov.getBoundingClientRect();\n    var nx = ptr.cx-rect.left, ny = ptr.cy-rect.top;\n    ptr.vx = nx-ptr.x; ptr.vy = ny-ptr.y; ptr.px=ptr.x; ptr.py=ptr.y; ptr.x=nx; ptr.y=ny;\n    var nowMs = now(); var dt = Math.min(50, nowMs-(lastT||nowMs)); lastT=nowMs;\n    var w = ov.clientWidth||layer.clientWidth, h = ov.clientHeight||layer.clientHeight;\n    var act = activeSet(); var on={}; act.forEach(function(id){on[id]=1;});\n    store.effects.forEach(function(eff){\n      if(!eff.enabled) return;\n      var r = instance(layer, eff);\n      if(on[eff.id]){\n        if(r.canvas.style.display==='none') r.canvas.style.display='block';\n        sizeCanvas(r, w, h);\n        if(r.inst&&r.inst.frame){ try{ r.inst.frame(dt); }catch(e){} }\n      }else if(r.canvas.style.display!=='none'){ r.canvas.style.display='none'; if(r.inst&&r.inst.clear){ try{r.inst.clear();}catch(e){} } }\n    });\n    var ids={}; store.effects.forEach(function(e){ids[e.id]=1;});\n    for(var k in inst){ if(!ids[k]){ try{ var rr=inst[k]; if(rr.inst&&rr.inst.destroy)rr.inst.destroy(); if(rr.canvas&&rr.canvas.parentNode)rr.canvas.parentNode.removeChild(rr.canvas);}catch(e){} delete inst[k]; } }\n  }\n  requestAnimationFrame(loop);\n})();\n";
var WKEY = 'vnm-weather';
function _whDefault(){ return { enabled:false, coverDialog:true, effects:[], random:{on:false,interval:20,comboMin:1,comboMax:2} }; }
function _whLoad(TOP){
  try{ var o=JSON.parse(TOP.localStorage.getItem(WKEY)||'null');
    if(!o||typeof o!=='object') return _whDefault();
    o.effects=o.effects||[]; o.random=o.random||{on:false,interval:20,comboMin:1,comboMax:2}; return o;
  }catch(e){ return _whDefault(); }
}
function _whSave(TOP,s){ try{ TOP.localStorage.setItem(WKEY, JSON.stringify(s)); return true; }catch(e){ return false; } }
/* 把渲染引擎注入顶层窗口（只注入一次）——引擎常驻 TOP，不随消息 iframe 销毁，
   这样设置里开了之后每次打开 VN 都会显示勾选的特效。 */
function _whInjectEngine(TOP){
  try{ var d=TOP.document; if(d.getElementById('vnm-weather-engine')) return;
    var s=d.createElement('script'); s.id='vnm-weather-engine'; s.textContent=ENGINE_SRC;
    (d.head||d.documentElement).appendChild(s);
  }catch(e){}
}
function _whBoot(TOP, ctx){
  var s=_whLoad(TOP);
  s.enabled = !!(ctx.settings && ctx.settings.enabled);
  s.coverDialog = ctx.settings ? (ctx.settings.coverDialog !== false) : true;
  _whSave(TOP,s);
  _whInjectEngine(TOP);
}

var TOP = window.parent, TOPDOC = TOP.document;
var DOC = (ctx.div('','')).ownerDocument || document;
_whBoot(TOP, ctx);
var store = _whLoad(TOP);
function persist(){ _whSave(TOP, store); _whInjectEngine(TOP); }

var root = ctx.div('',''); root.id = 'vnm-wth-root';
try{ var stl = DOC.createElement('style');
  stl.textContent = '#vnm-wth-root *{-webkit-tap-highlight-color:transparent !important;}'
   + '#vnm-wth-root button:focus,#vnm-wth-root [tabindex]:focus{outline:none !important;}'
   + '#vnm-wth-root input[type=range]{-webkit-appearance:none;appearance:none;height:4px;border-radius:4px;background:rgba(255,255,255,.18);outline:none;}'
   + '#vnm-wth-root input[type=range]::-webkit-slider-thumb{-webkit-appearance:none;width:16px;height:16px;border-radius:50%;background:rgba(255,255,255,.92);cursor:pointer;border:none;}'
   + '#vnm-wth-root input[type=range]::-moz-range-thumb{width:16px;height:16px;border-radius:50%;background:rgba(255,255,255,.92);cursor:pointer;border:none;}';
  root.appendChild(stl);
}catch(e){}

function check(on,cb){
  var b=ctx.div('',''); b.style.cssText='width:19px;height:19px;border-radius:6px;flex:0 0 auto;border:1.5px solid rgba(255,255,255,.3);display:flex;align-items:center;justify-content:center;cursor:pointer;transition:all .15s;'+(on?'background:rgba(255,255,255,.85);border-color:rgba(255,255,255,.85);':'');
  b.innerHTML=on?'<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#1c1c1e" stroke-width="3.2" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12l5 5L20 6"/></svg>':'';
  b.onclick=function(e){e.stopPropagation();cb();}; return b;
}
function chip(label,on,cb){
  var b=ctx.el('button','',label); b.style.cssText='flex:0 0 auto;padding:4px 11px;border-radius:999px;font-size:11px;cursor:pointer;transition:all .15s;border:1px solid rgba(255,255,255,'+(on?'.3':'.14')+');background:rgba(255,255,255,'+(on?'.16':'.04')+');color:rgba(255,255,255,'+(on?'.95':'.5')+');';
  b.onclick=function(e){e.stopPropagation();cb();}; return b;
}
function circle(svg,label,on,cb){
  var wrap=ctx.div(''); wrap.style.cssText='display:flex;flex-direction:column;align-items:center;gap:5px;flex:1;';
  var b=ctx.el('button','',''); b.style.cssText='width:46px;height:46px;border-radius:50%;display:flex;align-items:center;justify-content:center;cursor:pointer;transition:all .2s;border:1px solid rgba(255,255,255,'+(on?'.22':'.12')+');background:rgba(255,255,255,'+(on?'.16':'.05')+');';
  b.innerHTML='<svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,'+(on?'.95':'.6')+')" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">'+svg+'</svg>';
  b.onclick=cb;
  var t=ctx.div('',''); t.style.cssText='font-size:10px;color:rgba(255,255,255,'+(on?'.85':'.45')+');'; t.textContent=label;
  wrap.appendChild(b); wrap.appendChild(t); return wrap;
}

/* 顶部：说明 */
var seg=ctx.div(''); seg.style.cssText='display:flex;gap:6px;margin:2px 14px 12px;';
var infoBtn=ctx.el('button','','查看说明');
var SEGOFF='flex:1;border:1px solid rgba(255,255,255,.1);background:rgba(255,255,255,.05);color:rgba(255,255,255,.62);font-size:13px;padding:10px 4px;border-radius:12px;cursor:pointer;white-space:nowrap;';
var SEGON='flex:1;border:1px solid rgba(255,255,255,.16);background:rgba(255,255,255,.14);color:rgba(255,255,255,.95);font-size:13px;padding:10px 4px;border-radius:12px;cursor:pointer;white-space:nowrap;box-shadow:0 1px 6px rgba(0,0,0,.25);';
infoBtn.style.cssText=SEGOFF; seg.appendChild(infoBtn); root.appendChild(seg);

var infoCard=ctx.div('v8card',''); infoCard.style.cssText='display:none;font-size:12px;line-height:1.7;color:rgba(255,255,255,.7);padding:14px 16px;margin-bottom:12px;';
infoCard.innerHTML='<b style="color:rgba(255,255,255,.85)">天气</b> 在 VN 主界面叠加全屏动效（如下雨、水波纹）。每个动效是一个单独的 .json 特效文件，用下面「导入」加进来。<br><br><b style="color:rgba(255,255,255,.85)">方块卡片</b>=已导入的特效，勾选启用；点卡片展开可调它自己的密度/强度等参数（每个特效自带）。标「固定」的特效在随机模式下也始终显示。<br><br><b style="color:rgba(255,255,255,.85)">随机/组合</b>：开启后每隔一段时间随机挑选若干个非固定特效组合显示。<br><br>总开关在 主程序 设置 → 天气 里。导入的特效文件怎么写，见随附的开发说明 txt。';
infoBtn.onclick=function(){ var s=infoCard.style.display==='none'; infoCard.style.display=s?'block':'none'; infoBtn.style.cssText=s?SEGON:SEGOFF; };
root.appendChild(infoCard);

var listWrap=ctx.div(''); root.appendChild(listWrap);

/* 随机/组合 设置卡 */
function randomCard(){
  var c=ctx.div('v8card',''); c.style.cssText='padding:14px 16px;margin-bottom:12px;';
  var hd=ctx.div(''); hd.style.cssText='display:flex;align-items:center;gap:10px;';
  hd.appendChild(check(store.random.on,function(){store.random.on=!store.random.on;persist();render();}));
  var t=ctx.div(''); t.style.cssText='flex:1;font-size:14px;font-weight:600;color:rgba(255,255,255,.9);'; t.textContent='随机组合模式';
  hd.appendChild(t); c.appendChild(hd);
  if(store.random.on){
    var body=ctx.div(''); body.style.cssText='margin-top:12px;';
    body.appendChild(slider('切换间隔(秒)','interval',5,120,1,store.random.interval,function(v){store.random.interval=v;persist();}));
    body.appendChild(slider('同时最少','comboMin',0,6,1,store.random.comboMin,function(v){store.random.comboMin=Math.min(v,store.random.comboMax);persist();}));
    body.appendChild(slider('同时最多','comboMax',1,6,1,store.random.comboMax,function(v){store.random.comboMax=Math.max(v,store.random.comboMin);persist();}));
    c.appendChild(body);
  }
  return c;
}

function slider(label,key,min,max,step,val,cb){
  var f=ctx.div(''); f.style.cssText='margin-bottom:12px;';
  var top=ctx.div(''); top.style.cssText='display:flex;justify-content:space-between;font-size:11px;color:rgba(255,255,255,.5);margin-bottom:6px;';
  var l=ctx.div(''); l.textContent=label; var vv=ctx.div(''); vv.textContent=String(val); vv.style.color='rgba(255,255,255,.8)';
  top.appendChild(l); top.appendChild(vv); f.appendChild(top);
  var inp=ctx.el('input',''); inp.type='range'; inp.min=min; inp.max=max; inp.step=step; inp.value=val; inp.style.width='100%';
  inp.oninput=function(){ vv.textContent=inp.value; };
  inp.onchange=function(){ cb(parseFloat(inp.value)); };
  f.appendChild(inp); return f;
}

function effectCard(eff,i){
  var c=ctx.div('v8card','');
  var hd=ctx.div(''); hd.style.cssText='display:flex;align-items:center;gap:10px;padding:14px 16px;cursor:pointer;';
  hd.appendChild(check(eff.enabled,function(){eff.enabled=!eff.enabled;persist();render();}));
  var nm=ctx.div(''); nm.style.cssText='flex:1;font-size:14px;font-weight:600;color:rgba(255,255,255,'+(eff.enabled?'.9':'.45')+');white-space:nowrap;overflow:hidden;text-overflow:ellipsis;'; nm.textContent=eff.name||'未命名特效';
  hd.appendChild(nm);
  hd.appendChild(chip('固定',eff.fixed,function(){eff.fixed=!eff.fixed;persist();render();}));
  var car=ctx.div('',eff._open?'▾':'▸'); car.style.cssText='color:rgba(255,255,255,.3);font-size:12px;flex:0 0 auto;'; hd.appendChild(car);
  hd.onclick=function(){eff._open=!eff._open;render();};
  c.appendChild(hd);
  if(eff._open){
    var body=ctx.div(''); body.style.cssText='border-top:.5px solid rgba(255,255,255,.07);padding:12px 16px;';
    if(eff.description){ var d=ctx.div(''); d.style.cssText='font-size:11px;color:rgba(255,255,255,.45);margin-bottom:12px;line-height:1.5;'; d.textContent=eff.description; body.appendChild(d); }
    var defs=eff.paramDefs||[];
    if(!defs.length){ var none=ctx.div(''); none.style.cssText='font-size:11px;color:rgba(255,255,255,.35);'; none.textContent='此特效没有可调参数。'; body.appendChild(none); }
    defs.forEach(function(pd){
      var cur=(eff.params&&eff.params[pd.key]!=null)?eff.params[pd.key]:pd.default;
      body.appendChild(slider((pd.label||pd.key)+(pd.unit?(' ('+pd.unit+')'):''),pd.key,pd.min,pd.max,pd.step||1,cur,function(v){ eff.params=eff.params||{}; eff.params[pd.key]=v; persist(); }));
    });
    var del=ctx.el('button','v8btn del','删除此特效'); del.style.cssText='width:100%;margin-top:6px;';
    del.onclick=function(){ store.effects.splice(i,1); persist(); render(); };
    body.appendChild(del); c.appendChild(body);
  }
  return c;
}

/* 底部圆形按钮：随机 / 导入 / 导出 */
function bottomBar(){
  var bar=ctx.div('v8card',''); bar.style.cssText='display:flex;gap:6px;padding:14px 10px;margin-top:4px;';
  bar.appendChild(circle('<circle cx="12" cy="12" r="9"/><path d="M8 9h8M8 12h8M8 15h5"/>','随机',store.random.on,function(){store.random.on=!store.random.on;persist();render();}));
  bar.appendChild(circle('<path d="M12 3v12m0 0l-4-4m4 4l4-4"/><path d="M4 17v2a2 2 0 002 2h12a2 2 0 002-2v-2"/>','导入',false,importEffect));
  bar.appendChild(circle('<path d="M12 21V9m0 0l-4 4m4-4l4 4"/><path d="M4 7V5a2 2 0 012-2h12a2 2 0 012 2v2"/>','导出',false,exportEffects));
  return bar;
}

function importEffect(){
  var fin=DOC.createElement('input'); fin.type='file'; fin.accept='.json,application/json'; fin.style.display='none';
  fin.onchange=function(){ var f=fin.files&&fin.files[0]; if(!f) return; var fr=new (TOP.FileReader||FileReader)();
    fr.onload=function(){ try{ var o=JSON.parse(fr.result); var arr=o.effects?o.effects:[o];
      var n=0; arr.forEach(function(p){ if(!p||!p.code){return;} var params={}; (p.params||[]).forEach(function(pd){ params[pd.key]=pd.default; });
        store.effects.push({ id:'wfx'+Date.now()+Math.floor(Math.random()*1e5), name:p.name||'特效', description:p.description||'', code:p.code, enabled:true, fixed:false, params:params, paramDefs:p.params||[] }); n++; });
      persist(); render(); ctx.toast&&ctx.toast('已导入 '+n+' 个特效'); }
      catch(e){ ctx.toast&&ctx.toast('导入失败：文件格式不正确'); } };
    fr.readAsText(f); };
  TOPDOC.body.appendChild(fin); fin.click(); TOP.setTimeout(function(){ if(fin.parentNode)fin.parentNode.removeChild(fin); },3000);
}
function exportEffects(){
  if(!store.effects.length){ ctx.toast&&ctx.toast('没有可导出的特效'); return; }
  var out={ vnmWeatherBundle:true, effects: store.effects.map(function(e){
    var params=(e.paramDefs||[]).map(function(pd){ var v=(e.params&&e.params[pd.key]!=null)?e.params[pd.key]:pd.default; var c={}; for(var k in pd)c[k]=pd[k]; c.default=v; return c; });
    return { vnmWeatherEffect:true, name:e.name, description:e.description, params:params, code:e.code }; }) };
  try{ var blob=new (TOP.Blob||Blob)([JSON.stringify(out,null,2)],{type:'application/json'});
    var url=(TOP.URL||URL).createObjectURL(blob); var a=TOPDOC.createElement('a'); a.href=url; a.download='weather-effects-'+Date.now()+'.json';
    TOPDOC.body.appendChild(a); a.click(); a.remove(); TOP.setTimeout(function(){try{(TOP.URL||URL).revokeObjectURL(url);}catch(e){}},1500);
    ctx.toast&&ctx.toast('已导出 '+store.effects.length+' 个特效'); }catch(e){ ctx.toast&&ctx.toast('导出失败'); }
}

function render(){
  listWrap.innerHTML='';
  if(!store.effects.length){ var em=ctx.div(''); em.style.cssText='text-align:center;padding:24px 14px;color:rgba(255,255,255,.45);font-size:12px;'; em.textContent='还没有特效，点下方「导入」加载特效文件。'; listWrap.appendChild(em); }
  store.effects.forEach(function(e,i){ listWrap.appendChild(effectCard(e,i)); });
  listWrap.appendChild(randomCard());
  listWrap.appendChild(bottomBar());
}
render();
return root;

})

