(function(ctx){
var ENGINE_SRC = "(function(){
  if(window.__whEngine) return; window.__whEngine = true;
  var WKEY = 'vnm-weather';
  var lastRaw = null, store = { enabled:false, coverDialog:true, effects:[], random:{} };
  var inst = {};                 /* id -> {canvas,api,inst,code} */
  var ptr = { cx:0, cy:0, x:0, y:0, px:0, py:0, vx:0, vy:0, down:false, t:0, moved:0 };
  var rnd = { ids:null, last:0 };
  var boundDocs = [];
  var lastT = 0, downLayer = false;

  function now(){ return (window.performance&&performance.now)?performance.now():Date.now(); }

  function readStore(){
    try{
      var raw = localStorage.getItem(WKEY);
      if(raw !== lastRaw){
        lastRaw = raw;
        store = raw ? JSON.parse(raw) : { enabled:false, effects:[], random:{} };
        store.effects = store.effects || []; store.random = store.random || {};
        store.effects.forEach(function(e){ var r=inst[e.id]; if(r) r.api.params = e.params||{}; });
      }
    }catch(e){}
  }

  function findOverlay(){
    try{
